import Foundation

final class QuestionBank {
    private(set) var questions: [Question]

    init(allQuestions: [Question] = QuestionSeed.questions) {
        questions = allQuestions.filter(\.isPublishable)
    }

    func questions(chapterId: String? = nil, levelId: String? = nil, topic: String? = nil, subtopic: String? = nil, difficulty: String? = nil) -> [Question] {
        questions.filter { question in
            (chapterId == nil || question.chapterId == chapterId) &&
            (levelId == nil || question.levelId == levelId) &&
            (topic == nil || question.topic == topic) &&
            (subtopic == nil || question.subtopic == subtopic) &&
            (difficulty == nil || question.difficulty == difficulty)
        }
    }

    func question(id: String) -> Question? {
        questions.first { $0.id == id }
    }

    func skillAccuracy(from attempts: [AttemptRecord]) -> [(String, Double)] {
        let answered = attempts.compactMap { attempt -> (Question, Bool)? in
            guard let question = question(id: attempt.questionId) else { return nil }
            return (question, attempt.isCorrect)
        }
        var buckets: [String: (correct: Int, count: Int)] = [:]
        for (question, correct) in answered {
            for skill in question.skills {
                buckets[skill, default: (0, 0)].count += 1
                if correct { buckets[skill, default: (0, 0)].correct += 1 }
            }
        }
        return buckets.map { ($0.key, Double($0.value.correct) / Double($0.value.count)) }
            .sorted { $0.1 > $1.1 }
    }

    func errorCounts(from attempts: [AttemptRecord]) -> [(String, Int)] {
        Dictionary(grouping: attempts.compactMap(\.errorType), by: { $0 })
            .map { ($0.key, $0.value.count) }
            .sorted { $0.1 > $1.1 }
    }

    func recommendedReview(from attempts: [AttemptRecord], mastered: Set<String>) -> [Question] {
        let wrongIDs = attempts.filter { !$0.isCorrect }.map(\.questionId)
        return Array(Set(wrongIDs)).filter { !mastered.contains($0) }.compactMap(question(id:))
    }
}

