    private static let createdAt = ISO8601DateFormatter().date(from: "2026-05-26T00:00:00Z")!

    private static func q(
        _ id: String, _ levelId: String, _ title: String, _ story: String, _ subtopic: String, _ difficulty: String,
        _ text: String, _ answer: String, _ unit: String, _ type: AnswerType, _ options: [String],
        _ steps: [String], _ equations: [String], _ hints: [String], _ skills: [String],
        _ competencies: [String], _ errors: [String], _ commonWrong: [String],
        _ visual: VisualType, _ data: [String: String]
    ) -> Question {
        let chapterId = levelId.hasPrefix("1") ? "chapter-1" : "chapter-2"
        let topic = chapterId == "chapter-1" ? "行程问题" : "小学几何"
        let levelReward = AdventureContent.levels.first { $0.id == levelId }!.reward
        let feedback = Dictionary(uniqueKeysWithValues: commonWrong.map { ($0, "这个答案提示我们可能出现了“\(errors.first ?? "计算检查")”。试着看看路线图或图形，再算一次。") })
        return Question(
            id: id, chapterId: chapterId, levelId: levelId, title: title, storyContext: story,
            scene: AdventureContent.levels.first { $0.id == levelId }!.scene, topic: topic, subtopic: subtopic,
            gradeBand: "小学四年级", difficulty: difficulty,
            difficultyDescription: ["A": "基础公式", "B": "一步变式", "C": "多步应用", "D": "方程建模 / 小奥启蒙"][difficulty]!,
            questionText: text, answerType: type, options: options, correctAnswer: answer,
            acceptableAnswers: [answer, "\(answer)\(unit)"], unit: unit,
            solutionSteps: steps, equationSolution: equations, hints: hints, skills: skills,
            coreCompetencies: competencies, errorTypes: errors, commonWrongAnswers: commonWrong,
            wrongAnswerFeedback: feedback, visualType: visual, visualData: data, reward: levelReward,
            source: QuestionSource(
                sourceType: .original, sourceName: "卡皮巴拉海岛探险原创题库 v1",
                sourceUrl: nil, sourceReference: "参照《义务教育数学课程标准（2022年版）》相关学段知识主题自主命题",
                adaptationNote: "基于知识点和模型原创编写剧情、数据、题面与解法；未复制教材或竞赛原题。",
                licenseNote: "项目原创内容，可用于本应用发布前内部复核与发布。",
                author: "Product Content Team", reviewedBy: "MVP Content Review", createdAt: createdAt, updatedAt: createdAt
            ),
            reviewStatus: .approved, copyrightStatus: .original,
            notesForParent: "观察孩子是否掌握“\(skills.first ?? subtopic)”并能解释计算理由。"
        )
    }
